/* ===================== SIDEBAR ===================== */
.sidebar {
    -fx-background-color: linear-gradient(to bottom, #1298b7, #5b8fe7);
    -fx-pref-width: 250px;
    -fx-min-width: 250px;
    -fx-max-width: 250px;
}
.sidebar-btn {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-padding: 10 12;
    -fx-background-radius: 12px;
    -fx-cursor: hand;
}

.sidebar-btn:hover {
    -fx-background-color: rgba(255,255,255,0.08);
}

.sidebar-btn:focused {
    -fx-background-color: rgba(255,255,255,0.10);
    -fx-border-color: transparent;
}

.sidebar-btn .label {
    -fx-text-fill: white;
}
.logo-box {
    -fx-padding: 10 10 18 10;
    -fx-border-color: transparent transparent rgba(255,255,255,0.18) transparent;
    -fx-border-width: 0 0 1 0;
}

.logo-heart {
    -fx-font-size: 26px;
    -fx-text-fill: #ff2f3a;
    -fx-font-family: "Segoe UI Emoji";
}

.logo-plus {
    -fx-font-size: 16px;
    -fx-text-fill: #0fd3df;
    -fx-font-weight: bold;
    -fx-translate-y: 2;
}

.logo-text {
    -fx-font-size: 22px;
    -fx-font-weight: bold;
    -fx-text-fill: white;
}

.sidebar-separator {
    -fx-opacity: 0;
}

.sidebar-section-title {
    -fx-text-fill: #d9f3ff;
    -fx-font-size: 13px;
    -fx-font-weight: bold;
    -fx-padding: 12 0 8 0;
    -fx-letter-spacing: 1px;
}

.sidebar-item {
    -fx-padding: 10 12;
    -fx-spacing: 10;
    -fx-alignment: CENTER_LEFT;
    -fx-background-radius: 12px;
    -fx-cursor: hand;
