    -fx-font-size: 12px;
    -fx-font-weight: 900;
    -fx-padding: 8 14;
    -fx-background-radius: 999;
}

/* TABLEVIEW */
.admin-reclamation-table {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-table-cell-border-color: transparent;
    -fx-padding: 0;
}

.admin-reclamation-table .column-header-background {
    -fx-background-color: linear-gradient(to right, #0891b2, #2563eb);
    -fx-background-radius: 18 18 0 0;
    -fx-padding: 0 0 2 0;
}

.admin-reclamation-table .column-header {
    -fx-background-color: transparent;
    -fx-size: 48px;
    -fx-border-color: transparent;
}

.admin-reclamation-table .column-header .label {
    -fx-text-fill: white;
    -fx-font-weight: 900;
    -fx-font-size: 13px;
    -fx-alignment: CENTER;
}

.admin-reclamation-table .filler {
    -fx-background-color: transparent;
}

.admin-reclamation-table .table-row-cell {
    -fx-background-color: white;
    -fx-cell-size: 54px;
    -fx-border-color: transparent transparent #e2e8f0 transparent;
    -fx-border-width: 0 0 1 0;
}

.admin-reclamation-table .table-row-cell:odd {
    -fx-background-color: #f8fafc;
}

.admin-reclamation-table .table-row-cell:hover {
    -fx-background-color: #e0f2fe;
}

.admin-reclamation-table .table-row-cell:selected {
    -fx-background-color: #dbeafe;
}

.admin-reclamation-table .table-cell {
    -fx-text-fill: #0f172a;
    -fx-font-size: 13px;
    -fx-padding: 8 10;
    -fx-alignment: CENTER_LEFT;
    -fx-border-color: transparent;
}

/* DESCRIPTION PLUS LISIBLE */
.admin-reclamation-table .table-cell {
    -fx-wrap-text: true;
}

/* BOUTON RÉPONDRE DANS LA TABLE */
.admin-reclamation-table .button {
    -fx-background-color: linear-gradient(to right, #f59e0b, #f97316);
    -fx-text-fill: white;
    -fx-font-weight: 900;
    -fx-font-size: 12px;
    -fx-background-radius: 999;
    -fx-padding: 8 16;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(249, 115, 22, 0.25), 10, 0.2, 0, 3);
}

.admin-reclamation-table .button:hover {
    -fx-background-color: linear-gradient(to right, #d97706, #ea580c);
    -fx-scale-x: 1.03;
    -fx-scale-y: 1.03;
}

/* SCROLLBARS */
.admin-reclamation-table .scroll-bar:vertical {
    -fx-background-color: transparent;
}

.admin-reclamation-table .scroll-bar:vertical .thumb {
    -fx-background-color: #38bdf8;
    -fx-background-radius: 999;
}

.admin-reclamation-table .scroll-bar:horizontal {
    -fx-background-color: transparent;
}

.admin-reclamation-table .scroll-bar:horizontal .thumb {
    -fx-background-color: #38bdf8;
    -fx-background-radius: 999;
}

/* PLACEHOLDER */
.admin-reclamation-table .placeholder {
    -fx-background-color: #f8fafc;
}

