    -fx-background-radius: 999;
    -fx-padding: 8 17;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(249, 115, 22, 0.25), 10, 0.2, 0, 3);
}

.table-feature-view .button:hover {
    -fx-background-color: linear-gradient(to right, #d97706, #ea580c);
    -fx-scale-x: 1.03;
    -fx-scale-y: 1.03;
}

/* ---------- Scrollbar propre ---------- */

.table-feature-view .scroll-bar:vertical {
    -fx-background-color: transparent;
}

.table-feature-view .scroll-bar:vertical .thumb {
    -fx-background-color: #38bdf8;
    -fx-background-radius: 999;
}

.table-feature-view .scroll-bar:horizontal {
    -fx-background-color: transparent;
}

.table-feature-view .scroll-bar:horizontal .thumb {
    -fx-background-color: #38bdf8;
    -fx-background-radius: 999;
}

/* ---------- Placeholder tableau vide ---------- */

.table-feature-view .placeholder {
    -fx-background-color: #f8fafc;
}
